#!/bin/bash
#
# code/04_apply_fdr.sh
#
# Post-processes GWAS raw results with Benjamini-Hochberg FDR correction.
#
# Input:  data/interim/gwas_raw.tsv (generated by code/03_gwas.sh)
# Output: data/processed/gwas_results_fdr.tsv
#
# This script pipes the PLINK output through code/utils/fdr_correction.py.
#
set -euo pipefail

PROJECT_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
SCRIPT_DIR="${PROJECT_ROOT}/code"
DATA_DIR="${PROJECT_ROOT}/data"

INPUT_FILE="${DATA_DIR}/interim/gwas_raw.tsv"
OUTPUT_FILE="${DATA_DIR}/processed/gwas_results_fdr.tsv"

# Verify input exists (fail loudly if missing)
if [[ ! -f "${INPUT_FILE}" ]]; then
    echo "ERROR: Input file not found at ${INPUT_FILE}" >&2
    echo "Ensure code/03_gwas.sh has been executed successfully." >&2
    exit 1
fi

# Ensure output directory exists
mkdir -p "$(dirname "${OUTPUT_FILE}")"

echo "Running FDR correction on ${INPUT_FILE}..."

# Execute the Python FDR correction utility
# The script reads the input, applies BH correction, and writes the output with disclaimer
python3 "${SCRIPT_DIR}/utils/fdr_correction.py" \
    --input "${INPUT_FILE}" \
    --output "${OUTPUT_FILE}" \
    --p-col "P" \
    --q-col "Q"

if [[ $? -eq 0 ]] && [[ -f "${OUTPUT_FILE}" ]]; then
    echo "SUCCESS: FDR-corrected results written to ${OUTPUT_FILE}"
else
    echo "ERROR: FDR correction failed or output file missing." >&2
    exit 1
fi